PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE articles (     id INTEGER PRIMARY KEY AUTOINCREMENT,     slug TEXT UNIQUE NOT NULL,     title TEXT NOT NULL,     subtitle TEXT,     author TEXT,     published_at DATETIME DEFAULT CURRENT_TIMESTAMP,     read_time_minutes INTEGER,     image_url TEXT,     seo_description TEXT,     tags TEXT,     content_html TEXT NOT NULL );
CREATE TABLE authors (     id INTEGER PRIMARY KEY AUTOINCREMENT,     name TEXT UNIQUE NOT NULL,     role TEXT,     bio TEXT,     avatar_url TEXT,     social_link TEXT );
CREATE TABLE subscribers ( id INTEGER PRIMARY KEY AUTOINCREMENT, email TEXT UNIQUE NOT NULL, subscribed_at DATETIME DEFAULT CURRENT_TIMESTAMP );
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX idx_articles_slug ON articles (slug);
CREATE INDEX idx_articles_date ON articles (published_at DESC);
